+
+fn compute_cache_statistics(cache: &HashMap<String, Embedding>) -> CacheStatistics {
+    let size = cache.len();
+    let avg_norm = if size > 0 {
+        let total_norm: f32 = cache
+            .values()
+            .map(|emb| emb.iter().map(|x| x * x).sum::<f32>().sqrt())
+            .sum();
+        total_norm / size as f32
+    } else {
