+
+impl MemoryTracker {
+    fn new() -> Self {
+        Self {
+            initial_usage: get_current_memory_usage(),
+            peak: 0,
+        }
+    }
+
+    fn current_usage(&self) -> usize {
+        get_current_memory_usage() - self.initial_usage
+    }
+
+    fn peak_usage(&mut self) -> usize {
+        let current = self.current_usage();
+        self.peak = self.peak.max(current);
+        self.peak
+    }
+}
