+fn calculate_memory_growth(samples: &[usize]) -> f64 {
+    if samples.len() < 2 {
+        return 0.0;
+    }
+
+    let first = samples[0] as f64;
+    let last = samples[samples.len() - 1] as f64;
+
+    (last - first) / first
