+impl MemoryPool {
+    fn new(block_size: usize, count: usize) -> Self {
+        let blocks = (0..count)
+            .map(|_| vec![0u8; block_size])
+            .collect();
+        let available = (0..count).collect();
+
+        Self {
+            block_size,
+            blocks,
+            available,
+        }
+    }
+
+    fn allocate(&mut self) -> Option<usize> {
+        self.available.pop()
+    }
