+            Delimiter::Paren => ("(", ")"),
+            Delimiter::Bracket => ("[", "]"),
+            Delimiter::Brace => (r"\{", r"\}"),
+            Delimiter::Angle => (r"\langle", r"\rangle"),
+            Delimiter::Pipe => ("|", "|"),
