+    /// Load large images in chunks to minimize memory footprint
+    pub fn load_chunked<P: AsRef<Path>>(
+        &self,
+        path: P,
+        callback: impl Fn(&ImageBuffer<Rgba<u8>, Vec<u8>>) -> Result<(), ImageError>
+    ) -> Result<(), ImageError> {
